{
  "name": "Low-Income Home Energy Assistance Program (LIHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income must be at or below 200% of federal poverty guidelines (recent data: 1 person $3,278/month or $39,336/year; 2 people $4,287/month or $51,444/year; 3 people $5,296/month or $63,552/year; 4 people $6,304/month or $75,648/year; 5 people $7,313/month or $87,756/year; 6 people $8,322/month or $99,864/year). Older data confirms annual thresholds like 1 person $25,536, 2 people $34,488[1][2]. Defined as 60% of Delaware State Median Income after taxes[4].",
    "asset_limits": "No asset limits mentioned in Delaware state program sources.",
    "other_requirements": ["Household includes all at address sharing utility bill[1]", "Eligible heating fuels: electricity, natural gas, oil, kerosene, propane, coal, wood[4]", "Homeowners and renters qualify[2][4]", "Priority for elderly (60+), disabled, families with young children (5 and under), high energy burdens[3]"]
  },
  "benefits": {
    "type": "financial",
    "value": "Heating: $100 minimum to $2,561 maximum; Cooling: $1 minimum to $1,000 maximum; Crisis: up to $10,000. Average grant ~$553/year. Paid as supplemental grant to household or vendor for energy bills, crisis (e.g., shut-off), weatherization/repairs[1][4][5].",
    "varies_by": "household_size|priority_tier|fuel_type"
  },
  "application": {
    "methods": ["Online: Catholic Charities Diocese of Wilmington LIHEAP portal (via dhss.delaware.gov/dhss/dss/liheap.html)[4]", "Phone: (302) 255-9875[4]", "In-person/mail: Local agencies via Division of State Service Centers (DSSC), e.g., Catholic Charities[4][7]"],
    "processing_time": "Not specified; funding limited, applications may close early if funds exhausted[1]",
    "waitlist": "Possible pending status if documents incomplete; first-come-first-served until funds gone[3]",
    "forms": ["LIHEAP application (online via state portal or agency-specific)[4]"],
    "documents": ["Proof of income (last 30 days for adults)[3]", "Proof of residency/utility bill[3]", "Social Security cards (if applicable via tribal, but state not specified)[3]", "Shut-off notice or crisis proof for crisis aid[4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Statewide via DSSC and contractors like Catholic Charities; Delmarva Power customers highlighted but open to all[2][4][7]",
    "regional_variations": "Administered contractually by local agencies (e.g., Catholic Charities statewide); no specific county differences noted beyond potential fund exhaustion timing[4][7]",
    "offices_or_providers": ["Catholic Charities Diocese of Wilmington (statewide weatherization/LIHEAP)[4][7]", "Division of State Service Centers (DSSC)[4]"]
  },
  "official_source": "https://www.dhss.delaware.gov/dhss/dss/liheap.html",
  "gotchas": ["Funding limited; applications stop when funds run out, even before season end (heating Oct-Mar, cooling May-Aug, crisis year-round)[1][4]", "Household counts all sharing utility bill, unlike SNAP[1]", "Supplemental only, not full heating costs[4]", "Must apply during open periods; crisis needs proof like shut-off notice[1][4]", "Older data (e.g., 2021) may differ; verify current via official site[2]"],
  "data_shape_notes": "Benefits vary by income, size, fuel, crisis status; priority tiers for elderly/disabled/young kids; seasonal components with early fund exhaustion; statewide but local agency delivery"
}

{
  "name": "Delaware Senior Medicare Patrol (SMP/SHIP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; open to all Medicare beneficiaries, families, and caregivers[1][2][4]",
    "asset_limits": "No asset limits; no financial tests apply[1][2][4]",
    "other_requirements": ["Must be a Medicare beneficiary, family member, or caregiver in Delaware seeking help with Medicare fraud prevention/detection, health insurance counseling, or related issues[1][2][4][9]"]
  },
  "benefits": {
    "type": "service|advocacy",
    "value": "Free one-on-one counseling on Medicare options, enrollment, billing disputes, claims resolution; education on preventing/detecting/reporting Medicare fraud, errors, abuse; community presentations, health fairs; referrals to partners like CMS, OIG, state agencies; My Health Care Tracker tool for statements[1][2][3][9]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: Contact Delaware SMP/SHIP via national SMP locator or toll-free 877-808-2468 (connects to state program, Mon-Fri 9am-5:30pm ET)[5]", "Online: SMP Locator at smpresource.org to find Delaware contact; Delaware DHSS site dhss.delaware.gov/dsaapd for local details[5][9]", "In-person: Local sites via SMP locator (over 500 national sites, Delaware-specific through DHSS)[2][5]", "Contact form: smpresource.org contact for state connection[5]"],
    "processing_time": "Immediate phone counseling; individualized assistance upon contact (timely response within 2 business days via contact form)[5]",
    "waitlist": null,
    "forms": ["No specific application forms required; informal intake via phone/online for counseling[1][2][5]"],
    "documents": ["Medicare statements (MSNs), bills, Explanation of Benefits (EOB) for fraud/billing review; Medicare card if enrolling/discussing options[2][3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": null,
    "offices_or_providers": ["Administered statewide by Delaware Division of Services for Aging and Adults with Physical Disabilities (DSAAPD) under DHSS; local sites via SMP locator[5][9]"]
  },
  "official_source": "https://dhss.delaware.gov/dsaapd (Delaware SMP/SHIP); https://smpresource.org/smp-locator/ (national locator for Delaware contact)[5][9]",
  "gotchas": ["Not a financial assistance or healthcare provider program—focuses on education, fraud prevention, counseling (not direct medical care or cash benefits); often co-located with SHIP but distinct SMP anti-fraud mission; volunteers handle much outreach, so availability may depend on local staffing; must actively report suspected fraud[1][2][4][9]", "Automatic connection via national lines but confirm Delaware-specific counselor[5]"],
  "data_shape_notes": "no income/asset test; open to all Medicare beneficiaries/families; service-based (counseling/education) not financial; volunteer-driven with statewide coverage via single state grantee"
}

{
  "name": "Caregiver Support Program",
  "eligibility": {
    "age": 60,
    "income_limits": "Low-income requirements apply (specific dollar amounts or Federal Poverty Level thresholds not detailed in sources; varies by program and may align with Medicaid limits like 100-200% FPL by household size and category, e.g., children/pregnant women up to 200% FPL; contact DSAAPD for current table)[1][4]",
    "asset_limits": "Financial resources limits apply for long-term care programs (specific amounts not stated; what counts/exempts not detailed)[2][4]",
    "other_requirements": ["Functionally-impaired care recipients (age 60+ or 18-59 meeting financial/medical criteria)", "Caregivers providing 24-hour care to mentally/physically impaired persons needing supervision/ADL support", "Delaware residency", "US citizen or legal resident", "Care recipient meets nursing level of care or specified medical eligibility"][1][2][4]
  },
  "benefits": {
    "type": "service",
    "value": "Respite services (in-home or nursing home, regular or occasional); Caregiver Skills Training; Support Groups; Needs Assessment and Care Planning; Statewide Resource Centers; related services like personal care (dressing, bathing, toileting, feeding), transportation, health maintenance (specific hours/dollars not stated; varies by assessed need)[4]",
