  },
  "application": {
    "methods": ["Phone: 1-800-223-9074 (CARE Delaware/DSAAPD/Delaware ADRC)", "Website: https://www.dhss.delaware.gov/dsaapd (for info, providers, assistance)", "Contact Delaware Aging and Disability Resource Center (ADRC) for referral"],
    "processing_time": "Not specified",
    "waitlist": null,
    "forms": ["Eligibility requirements vary by program; no specific form names/numbers listed"],
    "documents": ["Proof of Delaware residency, income verification, medical/functional assessment details (prepare financial/medical eligibility proof for care recipient)"]
  },
  "geography": {
    "statewide": true,
    "restrictions": null,
    "regional_variations": "Services available statewide; contact DSAAPD for current list of locations/providers near you; potential regional wait times/providers not detailed[4]",
    "offices_or_providers": ["Delaware Aging and Disability Resource Center (ADRC)", "DSAAPD Resource Centers", "Joining Generations (for some services)"]
  },
  "official_source": "https://www.dhss.delaware.gov/dsaapd",
  "gotchas": ["Eligibility varies significantly by specific sub-program (e.g., respite vs. skills training); must contact CARE Delaware/DSAAPD for exact financial/medical criteria as not uniformly detailed online", "Care recipient must meet functional impairment and financial/medical tests; not all caregivers qualify without enrolled care recipient", "Separate from Medicaid waivers or paid family caregiver programs (e.g., Personal Attendant Services)", "Low-income focus but exact FPL/asset tables require direct inquiry[1][4][5]"],
  "data_shape_notes": "Eligibility varies by program/sub-service; low-income and functional impairment tests required; statewide but provider locations vary; no fixed dollar/hour benefits listed, needs-based; contact central line essential due to variable criteria"
}

{
  "name": "Legal Aid for Seniors",
  "eligibility": {
    "age": 60,
    "income_limits": "No fixed statewide dollar amounts specified in the state program; services available to all Delaware residents 60+ with priority to those with greatest social/economic need. Providers like Community Legal Aid Society (CLASI) and Legal Services Corporation of Delaware generally require income below 125% of Federal Poverty Guidelines (varies by program, household size, assets, and exceptions for seniors); exact FPL table not detailed—contact provider for current amounts.[1][2][3]",
    "asset_limits": "Assets considered on a case-by-case basis by providers; no statewide fixed limits specified. What counts and exemptions determined individually, potentially excluding primary home or certain personal items.[2][4]",
    "other_requirements": ["Delaware resident", "Priority to those with greatest social/economic need (e.g., low-income, rural residents)", "Legal matters limited to elder-related issues like public benefits (SS/SSI/SSDI, Medicaid/Medicare, veterans), housing/eviction, financial abuse/exploitation, nursing home discharges, powers of attorney, advance directives[1][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Free civil legal services including representation, advice, powers of attorney/advance directives, fraud/financial abuse cases, nursing home issues, housing/eviction defense, public benefits access (Medicare, Social Security, etc.). Providers conduct quarterly legal education programs. No specific dollar amounts or hours stated.[1][3]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": [
      "Phone: Community Legal Aid Society (CLASI) - New Castle: 302-575-0660, Kent: 302-674-8500, Sussex: 302-856-0038; Legal Services Corp of DE - New Castle: 302-575-0408, Kent: 302-734-8820[6]",
      "Online screening/referral: Legal Help Link (delegalhelplink.org) to match to provider[6]",
      "In-person: Local offices or courthouses for limited assistance programs[6]"
    ],
    "processing_time": "Not specified",
    "waitlist": "Not specified; priority-based allocation[1]",
    "forms": ["Complete application for services via provider intake (no specific form name/number listed)[2]"],
    "documents": ["Proof of age, income, assets, residency, details of legal issue (e.g., benefit denial letters, eviction notices); exact list varies by provider and case[2][4]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; providers must ensure statewide coverage[1]",
    "regional_variations": "Different offices/providers by county (New Castle, Kent, Sussex) with separate phone numbers; services coordinated via Division of Services for Aging but delivered locally. No specific wait time or service differences noted by region[1][6]",
    "offices_or_providers": ["Community Legal Aid Society, Inc. (CLASI) Elder Law Program (statewide focus, county offices)", "Legal Services Corporation of Delaware (county offices)", "Coordination with Division of Services for Aging and Adults with Physical Disabilities[1][3][6]"]
  },
  "official_source": "https://dhss.delaware.gov/wp-content/uploads/sites/2/dsaapd/pdf/SS_legal_svs_for_elderly.pdf",
  "gotchas": [
    "Not automatic eligibility at 60—providers apply their own income/asset guidelines (e.g., ~125% FPL) despite state 'all 60+' language; exceptions possible but call to confirm[1][2]",
    "Limited to specific elder-related civil matters (e.g., no criminal cases); priority to high-need cases may limit access[1][3]",
    "Assets reviewed case-by-case, can disqualify even if income qualifies[4]",
    "Funded by Older Americans Act Title III-B; subject to LSC restrictions[1]"
  ],
  "data_shape_notes": "State mandates statewide coverage for 60+ with priority tiers but delegates eligibility/assets to providers; county-specific offices/phone lines; no fixed income/asset tables or processing times published"
}

{
  "name": "Long-Term Care Ombudsman Program",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; program is available to all residents of long-term care facilities regardless of financial status[2][4][6]",
    "asset_limits": "No asset limits or tests apply[2][4][6]",
    "other_requirements": ["Must be a resident of a long-term care facility such as nursing home, assisted living residence, or related facility in Delaware[2][5][6]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Advocacy services including investigating and resolving complaints made by or on behalf of residents (except abuse/neglect/mistreatment/financial exploitation which are referred elsewhere); informing residents of rights under federal and state law; assisting in protecting rights; providing information about the program; periodic site visits and annual facility assessments to ensure care standards[2][4][5][6]",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Phone: 800-223-9074 or 1-800-223-9074[2][4]", "Website: www.dhss.delaware.gov/dhss or www.dhss.delaware.gov/dsaapd[2][4]"],
    "processing_time": "Not specified; complaint investigation occurs upon contact, with site visits as needed[5][6]",
    "waitlist": null,
    "forms": ["No specific application forms required; contact directly to file complaint or request assistance[2][6]"],
    "documents": ["No documents needed to request services; provide details of complaint or concern verbally or in writing[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; covers all long-term care facilities statewide[2][4][5]",
    "regional_variations": "Program operates statewide with regional volunteer coordinators (e.g., Kent/Sussex office exists), but core services uniform; no specified differences in wait times or provision[2][4][7]",
    "offices_or_providers": ["Main Administration Building, 1901 North DuPont Highway, New Castle, DE (statewide office)[2]", "Kent/Sussex regional program[7]"]
  },
  "official_source": "https://dhss.delaware.gov/dsaapd (Division of Services for Aging and Adults with Physical Disabilities)",
  "gotchas": ["Not a direct service provider like healthcare or financial aid—focuses solely on advocacy and rights protection, not personal care or funding[5][6]", "Abuse, neglect, mistreatment, or financial exploitation complaints are referred to Division of Long Term Care Residents Protection, not handled directly[6]", "Families cannot qualify independently; services are for facility residents only[2][5]", "Volunteers have strict conflict of interest rules (e.g., no family in facility)[2]"],
  "data_shape_notes": "no income test; advocacy-only for long-term care residents statewide; complaint-driven access with no formal application or waitlist"
}
